UPDATE tbl_account
SET email = #{email}, profile_img = #{profileImg}
WHERE username = #{username}

UPDATE tbl_account
SET profile_img = null, email = #{email}
WHERE username = #{username}

UPDATE tbl_account
SET enabled = FALSE, profile_img = null, disabled_at = NOW()
WHERE username = #{username}

UPDATE tbl_account
	SET password = #{password}
WHERE username = #{username}
